      reads this
    {
      0 <= count <= |buf| &&
      count == |model| &&
      0 <= head &&
      (|buf| == 0 ==> head == 0) &&
      (|buf| > 0 ==> head < |buf|)
    }

    constructor Init(capacity: nat, dynamic_: bool, powers_of_two_: bool)
      ensures Valid()
      ensures |buf| == capacity
      ensures head == 0 && count == 0
      ensures dynamic == dynamic_
      ensures powers_of_two == powers_of_two_
    {
      var d: T;
      d := *;
      fill := d;
      buf := seq(capacity, _ => d);
      head := 0;
      count := 0;
      model := [];
      dynamic := dynamic_;
      powers_of_two := powers_of_two_;
    }

    function capacity(): int
      reads this
      requires Valid()
    {
      |buf|
    }

    function readable_length(): int
      reads this
      requires Valid()
    {
      count
