    fn realloc(&mut self, new_size: usize) -> Result<(), AllocError> {
        // Zig: `self.allocator.realloc(self.buf, size)` preserving prefix.
        let mut new = Box::<[T]>::new_uninit_slice(new_size);
        let n = self.0.len().min(new_size);
